#!/usr/bin/env node

import { existsSync, readdirSync, readFileSync, writeFileSync } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const ROOT = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "../..");
const SUITES_DIR = path.join(ROOT, "evals", "suites");
const GENERATED_HEADER = [
  "# Generated by scripts/evals/compile-cases.mjs from cases.md.",
  "# Do not edit this file directly; edit cases.md in this suite instead.",
].join("\n");

const args = parseArgs(process.argv.slice(2));
const suites = args.suite ? [args.suite] : readdirSync(SUITES_DIR).sort();
let total = 0;

for (const suite of suites) {
  const suiteDir = path.join(SUITES_DIR, suite);
  const sourcePath = path.join(suiteDir, "cases.md");
  const outputPath = path.join(suiteDir, "cases.jsonl");
  if (!existsSync(sourcePath)) {
    if (args.suite) throw new Error(`No cases.md found for suite "${suite}"`);
    continue;
  }

  const cases = parseCasesMarkdown(readFileSync(sourcePath, "utf8"), { suite, sourcePath });
  const output = [GENERATED_HEADER, ...cases.map((evalCase) => JSON.stringify(evalCase))].join("\n");
  writeFileSync(outputPath, `${output}\n`);
  total += cases.length;
  console.log(`${path.relative(ROOT, outputPath)}: wrote ${cases.length} cases`);
}

console.log(`Compiled ${total} eval cases.`);

function parseArgs(argv) {
  const parsed = {};
  for (let index = 0; index < argv.length; index += 1) {
    const arg = argv[index];
    if (arg === "--suite") parsed.suite = readOptionValue(argv, ++index, "--suite");
    else if (arg === "--help" || arg === "-h") {
      console.log("Usage: node scripts/evals/compile-cases.mjs [--suite NAME]");
      process.exit(0);
    } else {
      throw new Error(`Unknown argument: ${arg}`);
    }
  }
  return parsed;
}

function readOptionValue(argv, index, option) {
  const value = argv[index];
  if (value === undefined || value.startsWith("--")) throw new Error(`${option} requires a value`);
  return value;
}

function parseCasesMarkdown(markdown, context) {
  return splitCaseBlocks(markdown).map((block) => parseCaseBlock(block, context));
}

function splitCaseBlocks(markdown) {
  const lines = markdown.split("\n");
  const blocks = [];
  let current = null;
  let inFence = false;
  for (const line of lines) {
    if (/^```/.test(line.trim())) {
      inFence = !inFence;
      if (current) current.lines.push(line);
      continue;
    }
    if (!inFence) {
      const match = /^##\s+([A-Za-z0-9_.:-]+)\s*$/.exec(line.trim());
      if (match) {
        if (current) blocks.push(current);
        current = { id: match[1], lines: [] };
        continue;
      }
    }
    if (current) current.lines.push(line);
  }
  if (current) blocks.push(current);
  return blocks;
}

function parseCaseBlock(block, context) {
  const sections = splitSections(block.lines);
  const meta = parseMetadata(sections.meta);
  const deterministic = parseKeyValueSection(sections["Deterministic Checks"] ?? []);
  const input = {};
  const message = sectionText(sections.Message);
  if (message) input.message = message;
  const operation = parseJsonSection(sections.Operation ?? sections.Operations);
  if (operation !== undefined) input.operation = operation;
  const useConfiguredMount = parseJsonSection(sections["Use Configured Mount"]);
  if (useConfiguredMount !== undefined) input.useConfiguredMount = Boolean(useConfiguredMount);

  if (!input.message && !input.operation) {
    throw new Error(`${context.sourcePath}: case ${block.id} needs Message or Operation(s)`);
  }

  const expected = { ...deterministic };
  const must = parseBullets([...(sections.Must ?? []), ...(sections["Human Must"] ?? [])]);
  const mustNot = parseBullets([...(sections["Must Not"] ?? []), ...(sections["Human Must Not"] ?? [])]);
  if (must.length > 0) expected.must = must;
  if (mustNot.length > 0) expected.mustNot = mustNot;
  if (meta.humanReview !== undefined) expected.humanReviewRequired = meta.humanReview;
  if (deterministic.humanReviewRequired !== undefined) expected.humanReviewRequired = deterministic.humanReviewRequired;

  const evalCase = {
    id: block.id,
    suite: meta.suite ?? context.suite,
    executor: meta.executor ?? "relayfile",
    kind: meta.kind ?? "capability",
    input,
    expected,
    tags: meta.tags ?? [],
  };
  if (meta.trials !== undefined) evalCase.trials = meta.trials;

  const mock = parseJsonSection(sections.Mock);
  if (mock !== undefined) evalCase.mock = mock;
  return evalCase;
}

function splitSections(lines) {
  const sections = { meta: [] };
  let current = "meta";
  for (const line of lines) {
    const match = /^###\s+(.+?)\s*$/.exec(line.trim());
    if (match) {
      current = match[1];
      sections[current] = [];
      continue;
    }
    sections[current].push(line);
  }
  return sections;
}

function parseMetadata(lines = []) {
  const values = {};
  for (const line of lines) {
    const trimmed = line.trim();
    if (!trimmed) continue;
    const match = /^([A-Za-z][A-Za-z ]*):\s*(.*)$/.exec(trimmed);
    if (!match) continue;
    const key = normalizeKey(match[1]);
    const value = parseScalar(match[2]);
    if (key === "tags") values.tags = splitCommaList(match[2]);
    else if (key === "trials") values.trials = Number(value);
    else if (key === "humanReview") values.humanReview = parseBoolean(value, "Human Review");
    else values[key] = value;
  }
  return values;
}

function parseKeyValueSection(lines = []) {
  const values = {};
  let currentKey = null;
  for (const line of lines) {
    const trimmed = line.trim();
    if (!trimmed) continue;
    const bullet = /^-\s+(.*)$/.exec(trimmed);
    if (bullet && currentKey) {
      if (!Array.isArray(values[currentKey])) values[currentKey] = [];
      values[currentKey].push(parseScalar(bullet[1]));
      continue;
    }

    const match = /^([A-Za-z][A-Za-z0-9 ]*):\s*(.*)$/.exec(trimmed);
    if (!match) continue;
    const key = normalizeKey(match[1]);
    const rawValue = match[2];
    if (rawValue.trim().length === 0) {
      values[key] = [];
      currentKey = key;
    } else {
      values[key] = arrayKeys().has(key) ? splitCommaList(rawValue).map(parseScalar) : parseScalar(rawValue);
      currentKey = key;
    }
  }
  return values;
}

function parseJsonSection(lines = []) {
  const text = sectionText(lines);
  if (!text) return undefined;
  const fence = /^```(?:json)?\s*\n([\s\S]*?)\n```\s*$/i.exec(text);
  const raw = fence ? fence[1] : text;
  return JSON.parse(raw);
}

function parseBullets(lines) {
  return lines.map((line) => /^-\s+(.*)$/.exec(line.trim())?.[1] ?? "").filter(Boolean);
}

function sectionText(lines = []) {
  return lines.join("\n").trim();
}

function splitCommaList(raw) {
  return String(raw).split(",").map((item) => item.trim()).filter(Boolean);
}

function parseScalar(raw) {
  const value = String(raw).trim();
  if (value === "true") return true;
  if (value === "false") return false;
  if (/^-?\d+$/.test(value)) return Number(value);
  if ((value.startsWith("{") && value.endsWith("}")) || (value.startsWith("[") && value.endsWith("]"))) {
    return JSON.parse(value);
  }
  return value;
}

function parseBoolean(value, label) {
  if (value === true || value === false) return value;
  throw new Error(`${label} must be true or false`);
}

function normalizeKey(key) {
  const words = key.trim().split(/\s+/).filter(Boolean);
  return words.map((word, index) => {
    const normalized = word.charAt(0).toUpperCase() + word.slice(1);
    return index === 0 ? normalized.charAt(0).toLowerCase() + normalized.slice(1) : normalized;
  }).join("");
}

function arrayKeys() {
  return new Set([
    "contentIncludes",
    "contentMatches",
    "forbidPhrases",
    "forbidPatterns",
    "toolCallsInclude",
    "toolCallsExclude",
    "fileExists",
    "fileNotExists",
    "fileContentIncludes",
    "fileContentEquals",
    "fileMetadata",
    "aclDenied",
    "writebackQueued",
    "noFilesModified",
    "metricLessThan",
    "metricGreaterThan",
  ]);
}
